
<script setup lang="ts">
import {computed,onMounted,ref} from 'vue'
import {useRouter} from 'vue-router'
import GlobalHeader from '../components/global/GlobalHeader.vue'
import GlobalFooter from '../components/global/GlobalFooter.vue'
import PageState from '../components/catalog/PageState.vue'
import {useAuth} from '../composables/useAuth'
import {mediaApi,profileApi,type MediaEntry,type ProfileData} from '../services/user-api'
const router=useRouter(),auth=useAuth(),data=ref<ProfileData>(),loading=ref(true),error=ref(''),tab=ref('activity'),editing=ref(false),form=ref({displayName:'',bio:'',avatarUrl:'',bannerUrl:'',profileVisibility:'public'}),password=ref({current:'',next:''}),notice=ref('')
const filtered=computed(()=>{const entries=data.value?.entries||[];if(tab.value==='want')return entries.filter(x=>x.watchStatus==='want');if(tab.value==='watching')return entries.filter(x=>x.watchStatus==='watching');if(tab.value==='watched')return entries.filter(x=>x.watchStatus==='watched');if(tab.value==='favorites')return entries.filter(x=>x.favorite);if(tab.value==='reviews')return entries.filter(x=>x.reviewText);return entries.slice(0,30)})
async function load(){loading.value=true;error.value='';try{data.value=await profileApi.own();const u=data.value.user;form.value={displayName:u.displayName,bio:u.bio,avatarUrl:u.avatarUrl,bannerUrl:u.bannerUrl,profileVisibility:u.profileVisibility}}catch(e){if(!auth.user.value)router.replace({name:'auth',query:{redirect:'/me'}});error.value=e instanceof Error?e.message:'加载失败'}finally{loading.value=false}}
async function save(){try{const result=await profileApi.update(form.value);if(data.value)data.value.user=result.user;editing.value=false;notice.value='资料已保存'}catch(e){notice.value=e instanceof Error?e.message:'保存失败'}}
async function changePassword(){try{await profileApi.password(password.value.current,password.value.next);notice.value='密码已修改，请重新登录';await auth.refresh();router.push({name:'auth'})}catch(e){notice.value=e instanceof Error?e.message:'修改失败'}}
async function clearHistory(type:'browse'|'search'){await profileApi.clearHistory(type);await load();notice.value='历史已清空'}
async function removeEntry(entry:MediaEntry){if(!confirm(`确定删除《${entry.title}》的全部个人记录吗？`))return;await mediaApi.remove(entry.mediaType,entry.tmdbId);await load();notice.value='记录已删除'}
function go(entry:MediaEntry){router.push({name:'title',params:{type:entry.mediaType,id:entry.tmdbId}})}
onMounted(load)
const tabs=[['activity','动态记录','history'],['want','想看','bookmark'],['watching','在看','visibility'],['watched','看过','done_all'],['reviews','评分与短评','reviews'],['favorites','个人收藏','favorite'],['history','浏览与搜索历史','manage_history'],['settings','账户设置','settings']]
</script>
<template><div class="min-h-screen bg-background text-on-surface"><GlobalHeader/><PageState :loading="loading" :error="error" @retry="load"><template v-if="data"><main class="pb-20 pt-[50px]"><section class="mx-auto mb-12 max-w-[1216px] px-4 pt-8 md:px-8"><div class="relative mb-[-60px] h-[260px] overflow-hidden rounded-xl group"><img :src="data.user.bannerUrl" class="h-full w-full object-cover opacity-60 transition-transform duration-700 group-hover:scale-105"><div class="absolute inset-0 bg-gradient-to-t from-background via-transparent to-transparent"></div></div><div class="relative z-10 flex flex-col items-end gap-8 md:flex-row"><img :src="data.user.avatarUrl" class="h-40 w-40 shrink-0 rounded-xl border-4 border-background bg-surface-container object-cover shadow-2xl"><div class="flex-1 pb-4"><div class="flex flex-wrap items-center gap-3"><h1 class="text-3xl font-extrabold">{{data.user.displayName}}</h1><span class="rounded-full bg-primary-container px-3 py-1 text-xs font-bold text-on-primary-container">{{data.user.role==='admin'?'管理员':'MovieScope 用户'}}</span></div><p class="mt-3 max-w-2xl text-on-surface-variant">{{data.user.bio||'还没有填写个人简介。'}}</p><p class="mt-2 text-xs text-outline">@{{data.user.username}} · 加入于 {{new Date(data.user.createdAt).toLocaleDateString('zh-CN')}}</p></div><button class="mb-4 rounded-lg bg-primary-container px-6 py-3 font-bold text-on-primary-container" @click="editing=true;tab='settings'"><span class="material-symbols-outlined mr-2 align-middle">edit</span>编辑资料</button></div></section><section class="mx-auto mb-12 grid max-w-[1216px] grid-cols-2 gap-4 px-4 md:grid-cols-4 md:px-8"><div v-for="item in [['已评分',data.stats.ratingCount],['短评',data.stats.reviewCount],['想看',data.stats.wantCount],['收藏',data.stats.favoriteCount]]" :key="item[0]" class="stat-card"><strong>{{item[1]||0}}</strong><span>{{item[0]}}</span></div></section><div class="mx-auto grid max-w-[1216px] gap-8 px-4 md:px-8 lg:grid-cols-[250px_1fr]"><aside><nav class="sticky top-20 space-y-2"><button v-for="item in tabs" :key="item[0]" class="profile-nav" :class="tab===item[0]?'active':''" @click="tab=item[0]"><span class="material-symbols-outlined">{{item[2]}}</span>{{item[1]}}</button><RouterLink v-if="data.user.role==='admin'" class="profile-nav" to="/admin"><span class="material-symbols-outlined">admin_panel_settings</span>管理后台</RouterLink></nav></aside><section class="min-w-0"><div class="mb-6 flex items-center justify-between border-b border-white/10 pb-4"><h2 class="text-2xl font-bold">{{tabs.find(x=>x[0]===tab)?.[1]}}</h2><p v-if="notice" class="text-sm text-primary">{{notice}}</p></div><template v-if="!['history','settings'].includes(tab)"><div v-if="filtered.length" class="grid grid-cols-2 gap-5 sm:grid-cols-3 lg:grid-cols-4"><button v-for="entry in filtered" :key="entry.id" class="group text-left" @click="go(entry)"><div class="aspect-[2/3] overflow-hidden rounded-lg bg-surface-container"><img :src="entry.posterUrl||''" :alt="entry.title" class="h-full w-full object-cover transition-transform duration-500 group-hover:scale-105"></div><h3 class="mt-3 truncate font-bold group-hover:text-primary">{{entry.title}}</h3><p class="mt-1 text-xs text-on-surface-variant">{{entry.releaseYear||'年份暂无'}} · {{entry.watchStatus==='want'?'想看':entry.watchStatus==='watching'?'在看':entry.watchStatus==='watched'?'看过':'已记录'}}</p><p v-if="entry.rating" class="mt-1 text-sm font-bold text-primary">我的评分 {{entry.rating.toFixed(1)}}</p><p v-if="entry.reviewText" class="mt-2 line-clamp-2 text-xs leading-5 text-on-surface-variant">{{entry.reviewText}}</p><button class="mt-2 text-xs text-red-300 opacity-0 transition-opacity group-hover:opacity-100" @click.stop="removeEntry(entry)">删除记录</button></button></div><div v-else class="empty-state">当前分类还没有记录。</div></template><template v-else-if="tab==='history'"><div class="space-y-10"><div><div class="mb-4 flex justify-between"><h3 class="font-bold">浏览历史</h3><button class="text-sm text-primary" @click="clearHistory('browse')">清空</button></div><div class="space-y-2"><RouterLink v-for="item in data.history?.browse||[]" :key="String(item.id)" :to="String(item.mediaType)==='person'?{name:'person',params:{id:String(item.sourceId)}}:{name:'title',params:{type:String(item.mediaType),id:String(item.sourceId)}}" class="history-row"><span>{{item.title}}</span><time>{{new Date(String(item.viewedAt)).toLocaleString('zh-CN')}}</time></RouterLink></div></div><div><div class="mb-4 flex justify-between"><h3 class="font-bold">搜索历史</h3><button class="text-sm text-primary" @click="clearHistory('search')">清空</button></div><div class="flex flex-wrap gap-2"><RouterLink v-for="item in data.history?.search||[]" :key="String(item.id)" :to="{name:'search',query:{q:String(item.queryText),type:String(item.searchType)}}" class="rounded-full bg-surface-container px-3 py-2 text-sm hover:text-primary">{{item.queryText}}</RouterLink></div></div></div></template><template v-else><form class="max-w-2xl space-y-5" @submit.prevent="save"><label class="form-label">显示名称<input v-model="form.displayName" class="form-input"></label><label class="form-label">个人简介<textarea v-model="form.bio" class="form-input min-h-28"></textarea></label><label class="form-label">头像 URL<input v-model="form.avatarUrl" class="form-input"></label><label class="form-label">背景图 URL<input v-model="form.bannerUrl" class="form-input"></label><label class="form-label">主页可见性<select v-model="form.profileVisibility" class="form-input"><option value="public">公开</option><option value="private">仅自己</option></select></label><button class="rounded-lg bg-primary-container px-6 py-3 font-bold text-on-primary-container">保存资料</button></form><form class="mt-12 max-w-2xl space-y-5 border-t border-white/10 pt-8" @submit.prevent="changePassword"><h3 class="text-xl font-bold">修改密码</h3><label class="form-label">当前密码<input v-model="password.current" type="password" class="form-input"></label><label class="form-label">新密码<input v-model="password.next" type="password" minlength="8" class="form-input"></label><button class="rounded-lg border border-white/10 px-6 py-3 font-bold hover:border-primary/40 hover:text-primary">修改密码</button></form></template></section></div></main></template></PageState><GlobalFooter/></div></template>
<style scoped>.stat-card{display:flex;flex-direction:column;align-items:center;border:1px solid rgba(255,255,255,.06);border-radius:12px;background:rgba(29,32,37,.75);padding:24px}.stat-card strong{font-size:32px;color:#f5c518}.stat-card span{margin-top:4px;font-size:12px;color:#c5c7ce}.profile-nav{display:flex;width:100%;align-items:center;gap:14px;border-radius:8px;padding:14px 16px;color:#c5c7ce;transition:.2s}.profile-nav:hover{background:#282a30;color:#e2e2e8}.profile-nav.active{background:#f5c518;color:#111;font-weight:700}.empty-state{border:1px dashed rgba(255,255,255,.1);border-radius:12px;padding:64px;text-align:center;color:#c5c7ce}.history-row{display:flex;justify-content:space-between;gap:20px;border-bottom:1px solid rgba(255,255,255,.05);padding:12px 0}.history-row:hover{color:#f5c518}.history-row time{font-size:12px;color:#777b84}.form-label{display:block;font-size:13px;font-weight:700;color:#c5c7ce}.form-input{margin-top:8px;width:100%;border:1px solid rgba(255,255,255,.1);border-radius:8px;background:#282a30;padding:12px;color:#e2e2e8;outline:none}.form-input:focus{border-color:rgba(245,197,24,.6)}</style>
